from dataclasses import dataclass, field
from typing import Any

@dataclass
class Goal:
    description: str
    is_leaf: bool = False
    result: Any = None
    children: list["Goal"] = field(default_factory=list)


class GoalStack:
    def __init__(self, final_goal: str):
        self._stack: list[Goal] = [Goal(description=final_goal)]

    def push(self, goal: Goal) -> None:
        self._stack.append(goal)

    def pop(self) -> Goal:
        return self._stack.pop()

    def peek(self) -> Goal | None:
        return self._stack[-1] if self._stack else None

    def is_empty(self) -> bool:
        return len(self._stack) == 0

    def __len__(self) -> int:
        return len(self._stack)

def execute_tree_with_retry(goal: Goal, context: dict, max_retries: int = 2) -> str:
    for child in goal.children:
        for attempt in range(max_retries + 1):
            try:
                execute_tree_with_retry(child, context, max_retries)
                break
            except Exception as e:
                if attempt == max_retries:
                    # Mark child as failed; parent will synthesize without it
                    child.result = f"[FAILED: {e}]"
                else:
                    # Add failure hint to context before retry
                    context[f"_retry_hint_{child.description[:30]}"] = str(e)

    if goal.is_leaf:
        goal.result = execute_leaf_goal(goal, context)
    else:
        child_results = {
            c.description: c.result
            for c in goal.children if c.result and not str(c.result).startswith("[FAILED")
        }
        context.update(child_results)
        goal.result = execute_leaf_goal(goal, context)

    return goal.result

TOOLS = [
    {
        "name": "read_file",
        "description": "Read the contents of a file by path",
        "input_schema": {
            "type": "object",
            "properties": {"path": {"type": "string", "description": "File path to read"}},
            "required": ["path"],
        },
    },
    {
        "name": "run_tests",
        "description": "Run the test suite and return pass/fail results",
        "input_schema": {
            "type": "object",
            "properties": {"filter": {"type": "string", "description": "Optional test name filter"}},
        },
    },
    {
        "name": "edit_file",
        "description": "Apply a patch to a file",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string"},
                "patch": {"type": "string", "description": "Unified diff patch content"},
            },
            "required": ["path", "patch"],
        },
    },
]

def dispatch_tool(name: str, inputs: dict) -> str:
    """Dispatch a tool call and return its string result."""
    if name == "read_file":
        with open(inputs["path"]) as f:
            return f.read()
    if name == "run_tests":
        import subprocess
        result = subprocess.run(
            ["python", "-m", "pytest", inputs.get("filter", ""), "-q"],
            capture_output=True, text=True
        )
        return result.stdout + result.stderr
    if name == "edit_file":
        import subprocess
        proc = subprocess.run(["patch", "-p1"], input=inputs["patch"], capture_output=True, text=True)
        return proc.stdout or proc.stderr
    raise ValueError(f"Unknown tool: {name}")


def execute_leaf_with_tools(goal: Goal, context: dict) -> str:
    """Execute a leaf goal, allowing the LLM to emit tool calls."""
    context_text = "\n".join(f"- {k[:40]}: {str(v)[:100]}" for k, v in context.items())
    messages = [{"role": "user", "content": f"Achieve this goal: {goal.description}\n\nContext:\n{context_text}"}]

    while True:
        response = client.messages.create(
            model=MODEL, max_tokens=1024,
            tools=TOOLS, messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if block.type == "text":
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
        messages.append({"role": "user", "content": tool_results})
